  it("rejects an imported archive ZIP when checksum details do not match file bytes", () => {
    const input = loadEngineeringSampleInput("distance_azimuth");
    const result = runEngineeringCalculation("distance_azimuth", input);
    const deliverables = buildEngineeringDeliverables(result, {
      inputFormat: "json",
      inputText: JSON.stringify(input, null, 2),
      sourceName: "distance-azimuth-sample.json",
      exportedAt: "2026-06-03T06:00:00.000Z",
    });
    const archive = buildEngineeringBatchArchiveZipExport([{ id: "distance-run", deliverables }], {
      batchName: "外部验收批次",
      exportedAt: "2026-06-03T06:30:00.000Z",
      preparedBy: "王工",
      reviewSignoff: {
        reviewer: "李工",
        conclusion: "approved",
        remarks: "可验收归档。",
        signedAt: "2026-06-03T06:30:00.000Z",
      },
    });
    const tampered = Buffer.from(archive.base64, "base64");
    const needle = Buffer.from("distance-azimuth-sample.json", "utf8");
    const offset = tampered.indexOf(
      needle,
      tampered.indexOf(Buffer.from("batch/batch-package.railwise-engineering-batch.json")),
    );
    expect(offset).toBeGreaterThan(0);
    tampered[offset] = tampered[offset] === 0x64 ? 0x44 : 0x64;

    const imported = verifyEngineeringArchiveZipImport(new Uint8Array(tampered), {
      archiveName: archive.fileName,
      checkedAt: "2026-06-03T07:00:00.000Z",
    });

    expect(imported.success).toBe(false);
    expect(imported.summary.checksumMismatchCount).toBeGreaterThan(0);
    expect(imported.summary.acceptanceDecision).toBe("reject");
    expect(imported.errors.join("\n")).toContain("checksum mismatch");
    expect(imported.checksumRows).toContainEqual(
      expect.objectContaining({
        path: "batch/batch-package.railwise-engineering-batch.json",
        status: "mismatch",
      }),
    );
    expect(imported.acceptanceReview.rows).toContainEqual(
      expect.objectContaining({
        evidenceStatus: "invalid",
        remediationPath: "重新生成完整归档 ZIP",
      }),
    );
  });

