  it("flags likely gross-error observations from standardized residuals", () => {
    const result = runEngineeringCalculation("control_network", {
      knownPoints: [
        { id: "A", x: 0, y: 0 },
        { id: "B", x: 100, y: 0 },
        { id: "C", x: 50, y: 100 },
      ],
      unknownPoints: [{ id: "P", x: 49.8, y: 40.2 }],
      observations: [
        { type: "distance", id: "AP-1", from: "A", to: "P", value: 64.03124, sigmaMm: 2 },
        { type: "distance", id: "AP-2", from: "A", to: "P", value: 64.06124, sigmaMm: 2 },
        { type: "distance", id: "BP", from: "B", to: "P", value: 64.03124, sigmaMm: 2 },
        { type: "distance", id: "CP", from: "C", to: "P", value: 60, sigmaMm: 2 },
        { type: "azimuth", id: "AZ-AP", from: "A", to: "P", value: 51.340191746, sigmaArcSec: 3 },
      ],
      residualToleranceMm: 5,
      standardizedResidualTolerance: 4,
    });

    expect(result.status).toBe("warn");
    expect(result.metrics.gross_error_standardized_threshold).toBe(4);
    expect(result.metrics.gross_error_candidate_count).toBe(2);
    expect(result.metrics.worst_observation_id).toBe("AP-2");
    expect(result.metrics.worst_observation_standardized_residual).toBeGreaterThan(8);
    expect(result.recommendations.join(" ")).toContain("AP-2");

    const residualRows = result.rows.filter((row) => row.row_type === "observation_residual");
    const worst = residualRows.find((row) => row.observation_id === "AP-2");
    expect(worst?.residual_rank).toBe(1);
    expect(worst?.quality_status).toBe("gross_error_candidate");
    expect(worst?.recommended_action).toBe("remeasure_or_downweight");

    const accepted = residualRows.find((row) => row.observation_id === "AZ-AP");
    expect(accepted?.quality_status).toBe("ok");
    expect(accepted?.recommended_action).toBe("accept");
  });

