  it("uses full GNSS baseline covariance matrices in the least-squares weight model", () => {
    const result = runEngineeringCalculation("control_network", {
      knownPoints: [
        { id: "A", x: 0, y: 0, z: 0 },
        { id: "B", x: 100, y: 0, z: 5 },
      ],
      unknownPoints: [{ id: "P", x: 49.8, y: 40.2, z: 3.7 }],
      observations: [
        {
          type: "gnss_baseline",
          id: "BL1",
          from: "A",
          to: "P",
          dx: 50.004,
          dy: 39.996,
          dz: 4,
          covarianceMatrixM2: [
            [0.000004, 0.000003, 0],
            [0.000003, 0.000009, 0],
            [0, 0, 0.000004],
          ],
        },
        {
          type: "gnss_baseline",
          id: "BL2",
          from: "B",
          to: "P",
          dx: -50,
          dy: 40.002,
          dz: -1,
          sigmaMm: 1,
        },
      ],
      coordinateToleranceMm: 50,
      residualToleranceMm: 10,
    });

    expect(result.status, JSON.stringify(result, null, 2)).toBe("ok");
    expect(result.metrics.baseline_covariance_matrix_count).toBe(1);
    expect(result.metrics.max_standardized_residual).toBeCloseTo(2.9588, 4);

    const pointRow = result.rows.find(
      (row) => row.row_type === "gnss_point" && row.point_id === "P",
    );
    expect(pointRow?.adjusted_x).toBeCloseTo(50.001415, 6);
    expect(pointRow?.adjusted_y).toBeCloseTo(40.000976, 6);

    const covarianceResidual = result.rows.find(
      (row) => row.row_type === "gnss_baseline_residual" && row.observation_id === "BL1",
    );
    expect(covarianceResidual?.covariance_model).toBe("full_3x3");
    expect(covarianceResidual?.sigma_x_mm).toBeCloseTo(2, 6);
    expect(covarianceResidual?.sigma_y_mm).toBeCloseTo(3, 6);
    expect(covarianceResidual?.sigma_z_mm).toBeCloseTo(2, 6);
    expect(covarianceResidual?.mahalanobis_residual).toBeCloseTo(2.9588, 4);
  });

