  it("builds whitelisted PROJ, GDAL, and PDAL command plans", () => {
    expect(ENGINEERING_ENGINE_WORKFLOWS.map((workflow) => workflow.id)).toEqual([
      "proj_crs_pipeline",
      "proj_transform_points",
      "gdal_vector_info",
      "gdal_vector_convert",
      "pdal_pointcloud_info",
      "pdal_icp_registration",
      "pdal_crop_bounds",
      "pdal_decimation",
      "pdal_voxel_sample",
    ]);

    const projPlan = buildEngineeringEngineCommandPlan("proj_crs_pipeline", {
      sourceCrs: "EPSG:4547",
      targetCrs: "EPSG:4326",
    });
    expect(projPlan.binary).toBe("projinfo");
    expect(projPlan.args).toEqual(["-s", "EPSG:4547", "-t", "EPSG:4326", "-o", "PROJJSON"]);

    const cctPlan = buildEngineeringEngineCommandPlan("proj_transform_points", {
      operation: "+proj=utm +zone=32 +ellps=GRS80",
      pointsText: "12 55 0 0",
    });
    expect(cctPlan.binary).toBe("cct");
    expect(cctPlan.args).toEqual(["+proj=utm", "+zone=32", "+ellps=GRS80"]);
    expect(cctPlan.stdin).toBe("12 55 0 0");
    expect(buildEngineeringEngineShellCommand(cctPlan)).toBe(
      "printf '%s\\n' '12 55 0 0' | cct +proj=utm +zone=32 +ellps=GRS80",
    );

    const vectorInfo = buildEngineeringEngineCommandPlan("gdal_vector_info", {
      inputPath: "/tmp/alignment.dxf",
    });
    expect(vectorInfo.binary).toBe("ogrinfo");
    expect(vectorInfo.args).toEqual(["-json", "-so", "-al", "/tmp/alignment.dxf"]);

    const vectorConvert = buildEngineeringEngineCommandPlan("gdal_vector_convert", {
      inputPath: "/tmp/alignment.dxf",
      outputPath: "/tmp/alignment.geojson",
      outputFormat: "GeoJSON",
      layerName: "TrackCenter",
      selectFields: "name,station_m,signed_offset_m",
      whereClause: "status <> 'ok'",
    });
    expect(vectorConvert.binary).toBe("ogr2ogr");
    expect(vectorConvert.args).toEqual([
      "-f",
      "GeoJSON",
      "-select",
      "name,station_m,signed_offset_m",
      "-where",
      "status <> 'ok'",
      "/tmp/alignment.geojson",
      "/tmp/alignment.dxf",
      "TrackCenter",
    ]);

    const pdalInfo = buildEngineeringEngineCommandPlan("pdal_pointcloud_info", {
      inputPath: "/tmp/scan.laz",
    });
    expect(pdalInfo.binary).toBe("pdal");
    expect(pdalInfo.args).toEqual(["info", "--metadata", "/tmp/scan.laz"]);

    const pdalIcp = buildEngineeringEngineCommandPlan("pdal_icp_registration", {
      fixedInputPath: "/tmp/fixed.laz",
      movingInputPath: "/tmp/moving.laz",
      outputPath: "/tmp/registered.laz",
      maxIterations: "80",
    });
    expect(pdalIcp.binary).toBe("pdal");
    expect(pdalIcp.args).toEqual([
      "pipeline",
      "--stdin",
      "--metadata",
      "/tmp/registered.laz.icp-metadata.json",
    ]);
    expect(JSON.parse(pdalIcp.stdin ?? "{}").pipeline).toEqual([
      "/tmp/fixed.laz",
      "/tmp/moving.laz",
      { type: "filters.icp", max_iter: 80 },
      "/tmp/registered.laz",
    ]);
    expect(pdalIcp.outputPath).toBe("/tmp/registered.laz");

    const pdalCrop = buildEngineeringEngineCommandPlan("pdal_crop_bounds", {
      inputPath: "/tmp/scan.laz",
      outputPath: "/tmp/cropped.laz",
      bounds: "([0,100],[0,100],[0,50])",
    });
    expect(JSON.parse(pdalCrop.stdin ?? "{}").pipeline).toEqual([
      "/tmp/scan.laz",
      { type: "filters.crop", bounds: "([0,100],[0,100],[0,50])" },
      "/tmp/cropped.laz",
    ]);

    const pdalDecimation = buildEngineeringEngineCommandPlan("pdal_decimation", {
      inputPath: "/tmp/scan.laz",
      outputPath: "/tmp/thin.laz",
      step: "10",
    });
    expect(JSON.parse(pdalDecimation.stdin ?? "{}").pipeline[1]).toEqual({
      type: "filters.decimation",
      step: 10,
    });

    const pdalVoxel = buildEngineeringEngineCommandPlan("pdal_voxel_sample", {
      inputPath: "/tmp/scan.laz",
      outputPath: "/tmp/voxel.laz",
      cell: "0.25",
    });
    expect(JSON.parse(pdalVoxel.stdin ?? "{}").pipeline[1]).toEqual({
      type: "filters.voxelcenternearestneighbor",
      cell: 0.25,
    });
    expect(() => buildEngineeringEngineCommandPlan("gdal_vector_info", { inputPath: "" })).toThrow(
      "inputPath",
    );
  });

