  it("builds a professional CSV sample package for field template handoff", () => {
    const pack = buildEngineeringProfessionalCsvSamplePack({
      exportedAt: "2026-06-06T09:20:00.000Z",
    });
    const samples = getEngineeringProfessionalCsvSamples();
    const zipText = Buffer.from(pack.base64, "base64").toString("utf8");

    expect(pack.schema).toBe("railwise.engineering.professionalCsvSamplePack.v1");
    expect(pack.fileName).toBe("railwise-professional-csv-samples.zip");
    expect(pack.mimeType).toBe("application/zip");
    expect(pack.sampleCount).toBe(samples.length);
    expect(pack.entryCount).toBe(samples.length + 3);
    expect(pack.csvIndex).toContain("tool_id,tool_title,sample_id,title,path,description");
    expect(pack.markdown).toContain("# Railwise 专业 CSV 样表包");
    expect(pack.markdown).toContain("导入内业平差工作台或轨道测量监测工具");
    expect(pack.markdown).not.toContain("导入工程分析工作台");
    expect(zipText).toContain("manifest.json");
    expect(zipText).toContain("README.md");
    expect(zipText).toContain("sample-index.csv");
    expect(zipText).toContain("samples/track_geometry_review/track-geometry-inspection-sample.csv");
    expect(zipText).toContain("samples/shield_guidance/shield-guidance-pose-sample.csv");
    expect(zipText).toContain("线路,里程,设计轨距(mm)");
    expect(zipText).toContain("盾构环号,推进日期,设计X(m)");
    expect(zipText).toContain("水平偏差(mm),高程偏差(mm),方位角偏差(°)");
    expect(JSON.parse(pack.manifest).sampleCount).toBe(samples.length);
  });

